#!/usr/bin/env node
/**
 * Build src/data/bigfive-occupation-profiles.json from the Anni et al. (2024)
 * supplementary dataset, mapped from ISCO-08 4-digit groups onto O*NET-SOC
 * codes via the official ESCO ↔ O*NET crosswalk and the ESCO occupation
 * taxonomy (which records each ESCO occupation's parent ISCO group).
 *
 * Pipeline:
 *   1. Read scripts/input/anni-bigfive-profiles.json (263 ISCO-4d profiles,
 *      scale = T-scores mean=50 SD=10). Generated by extract-anni-s6.py
 *      from the OSF supplementary-tables.xlsx (node m9sw3).
 *   2. Read data-raw/esco/tabiya-occupations.csv (3007 ESCO occupations with
 *      their parent ISCOGROUPCODE; auto-downloaded via tabiya-tech mirror).
 *   3. Read data-raw/esco/onet-esco-crosswalk.csv (4253 O*NET↔ESCO pairs;
 *      downloaded by build-esco-german.mjs — auto-fetched if missing).
 *   4. For each crosswalk row, resolve the ESCO side to an ISCO-4d code:
 *      direct ISCO URIs (`.../esco/isco/C####`) parse inline, ESCO
 *      occupation URIs (`.../esco/occupation/<uuid>`) look up via the
 *      tabiya occupation table.
 *   5. For each O*NET code, collect all Anni profiles whose ISCO-4d code
 *      appears among its crosswalk partners and average them unweighted.
 *      X-suffix aggregate codes (e.g. `101x`) are skipped — they are not
 *      real ISCO codes, just reporting groups Anni et al. coined for
 *      respondents whose titles spanned multiple 4d groups.
 *   6. Write src/data/bigfive-occupation-profiles.json. Schema is unchanged
 *      from the mock file — only meta + values differ.
 *
 * Usage:
 *   node scripts/build-bigfive-profiles.mjs
 */
import { existsSync, mkdirSync, readFileSync, writeFileSync } from 'node:fs'
import { dirname, join } from 'node:path'
import { fileURLToPath } from 'node:url'
import { spawnSync } from 'node:child_process'
import { parse } from 'csv-parse/sync'

const __dirname = dirname(fileURLToPath(import.meta.url))
const ROOT = join(__dirname, '..')

const ANNI_INPUT = join(ROOT, 'scripts/input/anni-bigfive-profiles.json')
const CORPUS_PATH = join(ROOT, 'src/data/onet-occupations.json')
const ESCO_DIR = join(ROOT, 'data-raw/esco')
const CROSSWALK_PATH = join(ESCO_DIR, 'onet-esco-crosswalk.csv')
const CROSSWALK_URL =
  'https://esco.ec.europa.eu/system/files/2023-08/ONET_%28Occupations%29_0_updated.csv'
const TABIYA_PATH = join(ESCO_DIR, 'tabiya-occupations.csv')
const TABIYA_URL =
  'https://raw.githubusercontent.com/tabiya-tech/tabiya-open-dataset/main/tabiya-esco-v1.1.1/csv/occupations.csv'
const OUTPUT = join(ROOT, 'src/data/bigfive-occupation-profiles.json')

// OCEAN order — matches existing consumer code (matcher.ts, types.ts).
const DIMENSIONS = ['openness', 'conscientiousness', 'extraversion', 'agreeableness', 'neuroticism']

function ensureDownload(path, url) {
  if (existsSync(path)) return
  mkdirSync(dirname(path), { recursive: true })
  console.log(`Downloading ${url} ...`)
  const res = spawnSync('curl', ['-sSL', '-o', path, url], { stdio: 'inherit' })
  if (res.status !== 0) throw new Error(`curl failed downloading ${url}`)
}

function loadAnniProfiles() {
  const raw = JSON.parse(readFileSync(ANNI_INPUT, 'utf-8'))
  const byIsco = new Map()
  let skipped = 0
  for (const p of raw.profiles) {
    // Skip aggregate X-suffix codes (e.g. 101x, 200x); not valid ISCO-08 codes.
    if (/x/i.test(p.iscoCode)) {
      skipped++
      continue
    }
    byIsco.set(p.iscoCode, p)
  }
  console.log(`Anni profiles: ${byIsco.size} real ISCO-4d codes (+${skipped} X-aggregate codes skipped)`)
  return { byIsco, source: raw.source }
}

function loadEscoToIsco() {
  ensureDownload(TABIYA_PATH, TABIYA_URL)
  const csv = readFileSync(TABIYA_PATH, 'utf-8')
  const rows = parse(csv, { columns: true, skip_empty_lines: true })
  const byUri = new Map()
  for (const row of rows) {
    if (!row.ORIGINURI || !row.ISCOGROUPCODE) continue
    byUri.set(row.ORIGINURI.trim(), row.ISCOGROUPCODE.trim())
  }
  console.log(`ESCO → ISCO map: ${byUri.size} occupations`)
  return byUri
}

function resolveIscoFromEscoUri(uri, escoToIsco) {
  // Direct ISCO URIs: http://data.europa.eu/esco/isco/C1221 → 1221
  const direct = uri.match(/\/esco\/isco\/C(\d{4})$/)
  if (direct) return direct[1]
  return escoToIsco.get(uri) ?? null
}

function loadCrosswalk() {
  ensureDownload(CROSSWALK_PATH, CROSSWALK_URL)
  const csv = readFileSync(CROSSWALK_PATH, 'utf-8')
  // Crosswalk CSV has 14 metadata rows before the header; csv-parse tolerates
  // variable column counts, so we strip them manually by column-count heuristic.
  const rows = parse(csv, {
    columns: false,
    skip_empty_lines: true,
    relax_column_count: true,
  })
  // Data rows are 7 columns starting with an O*NET-SOC code (NN-NNNN.NN).
  const pairs = []
  for (const row of rows) {
    if (row.length < 7) continue
    const onetCode = row[0]
    const escoUri = row[3]
    if (!/^\d{2}-\d{4}\.\d{2}$/.test(onetCode) || !escoUri) continue
    pairs.push({ onetCode, escoUri })
  }
  console.log(`Crosswalk pairs: ${pairs.length}`)
  return pairs
}

function average(values) {
  return values.reduce((a, b) => a + b, 0) / values.length
}

function profileFromContribs(contribs) {
  const out = {}
  for (const dim of DIMENSIONS) {
    out[dim] = Number(average(contribs.map((p) => p.scores[dim])).toFixed(2))
  }
  return out
}

// ISCO-3d / 2d sibling cascade: for an O*NET code whose resolved 4d groups
// have no Anni profile, fall back to averaging all Anni profiles sharing the
// same first 3 (then 2) digits as any resolved 4d. Recovers ~150/169 corpus
// codes that would otherwise have a null bigFiveModifier at runtime.
function siblingsAtPrefix(anniByIsco, isco4dSet, prefixLen) {
  const out = new Set()
  for (const code of isco4dSet) {
    const prefix = code.slice(0, prefixLen)
    for (const anniCode of anniByIsco.keys()) {
      if (anniCode.startsWith(prefix)) out.add(anniCode)
    }
  }
  return out
}

function buildProfiles(anniByIsco, escoToIsco, crosswalk) {
  // O*NET code → Set of resolved ISCO-4d codes (regardless of Anni coverage)
  const onetToIsco4d = new Map()
  let unresolved = 0
  for (const { onetCode, escoUri } of crosswalk) {
    const iscoCode = resolveIscoFromEscoUri(escoUri, escoToIsco)
    if (!iscoCode) {
      unresolved++
      continue
    }
    if (!onetToIsco4d.has(onetCode)) onetToIsco4d.set(onetCode, new Set())
    onetToIsco4d.get(onetCode).add(iscoCode)
  }
  console.log(`ESCO URIs with unresolvable ISCO: ${unresolved}`)

  const profiles = {}
  const profileSources = {}
  const counts = {
    '4d-direct': 0,
    '3d-imputed': 0,
    '2d-imputed': 0,
    'soc-sibling-imputed': 0,
    'no-recovery': 0,
  }

  for (const [onetCode, iscoSet] of onetToIsco4d) {
    const direct = [...iscoSet].filter((c) => anniByIsco.has(c))
    if (direct.length > 0) {
      profiles[onetCode] = profileFromContribs(direct.map((c) => anniByIsco.get(c)))
      profileSources[onetCode] = '4d-direct'
      counts['4d-direct']++
      continue
    }

    const sib3 = siblingsAtPrefix(anniByIsco, iscoSet, 3)
    if (sib3.size > 0) {
      profiles[onetCode] = profileFromContribs([...sib3].map((c) => anniByIsco.get(c)))
      profileSources[onetCode] = '3d-imputed'
      counts['3d-imputed']++
      continue
    }

    const sib2 = siblingsAtPrefix(anniByIsco, iscoSet, 2)
    if (sib2.size > 0) {
      profiles[onetCode] = profileFromContribs([...sib2].map((c) => anniByIsco.get(c)))
      profileSources[onetCode] = '2d-imputed'
      counts['2d-imputed']++
      continue
    }

    counts['no-recovery']++
  }

  return { profiles, profileSources, counts }
}

// SOC-sibling fallback: corpus codes with no ESCO-crosswalk row at all bypass
// the ISCO cascade entirely. For each such code, average the profiles of any
// other O*NET code sharing the same SOC-detail prefix (first 7 chars,
// "NN-NNNN") that the cascade did map. Recovers ~4 of the 19 Bucket-A codes.
// The remaining ~15 have no SOC-detail siblings and need hand-curation.
function applySocSiblingFallback(profiles, profileSources, counts, corpus) {
  const allMappedCodes = Object.keys(profiles)
  for (const occ of corpus) {
    if (profiles[occ.onetCode]) continue
    const socDetail = occ.onetCode.slice(0, 7)
    const siblings = allMappedCodes.filter(
      (code) => code !== occ.onetCode && code.startsWith(socDetail),
    )
    if (siblings.length === 0) continue
    const out = {}
    for (const dim of DIMENSIONS) {
      out[dim] = Number(average(siblings.map((s) => profiles[s][dim])).toFixed(2))
    }
    profiles[occ.onetCode] = out
    profileSources[occ.onetCode] = 'soc-sibling-imputed'
    counts['soc-sibling-imputed']++
  }
}

function main() {
  const { byIsco: anniByIsco, source } = loadAnniProfiles()
  const escoToIsco = loadEscoToIsco()
  const crosswalk = loadCrosswalk()
  const corpus = JSON.parse(readFileSync(CORPUS_PATH, 'utf-8'))

  const { profiles, profileSources, counts } = buildProfiles(anniByIsco, escoToIsco, crosswalk)
  applySocSiblingFallback(profiles, profileSources, counts, corpus)
  console.log(
    `Profiles by source: 4d=${counts['4d-direct']} 3d-imputed=${counts['3d-imputed']} 2d-imputed=${counts['2d-imputed']} soc-sibling-imputed=${counts['soc-sibling-imputed']}`,
  )
  const onetCount = Object.keys(profiles).length

  const output = {
    meta: {
      source: source.citation,
      doi: source.doi,
      osf: source.osf,
      table: source.table,
      license: 'Data CC BY 4.0 (author-approved use, 2026-04-14)',
      mock: false,
      dimensions: DIMENSIONS,
      scale: source.scale,
      iscoMapping: `${onetCount} O*NET codes mapped via ESCO crosswalk + ESCO occupation taxonomy: ${counts['4d-direct']} direct ISCO-4d, ${counts['3d-imputed']} imputed from ISCO-3d siblings, ${counts['2d-imputed']} imputed from ISCO-2d siblings, ${counts['soc-sibling-imputed']} imputed from SOC-detail siblings (no crosswalk)`,
      profileSourceCounts: counts,
    },
    profileSources,
    profiles,
  }

  writeFileSync(OUTPUT, JSON.stringify(output, null, 2) + '\n', 'utf-8')
  console.log(`Wrote ${onetCount} O*NET profiles to ${OUTPUT}`)
}

main()
